   #[tokio::test]
   async fn test_degradation_delay_debounces() {
       let mut harness = TestHarness::with_config(r#"
           [settings]
           degradation_policy = "fail_closed"
           degradation_delay_secs = 10
           health_check_interval_secs = 1
           consecutive_failures_threshold = 1

           [[proxies]]
           id = "proxy-a"
           url = "http://localhost:MOCK1_PORT"
       "#).await;

       // Brief failure then recovery
       let mock = harness.add_mock_proxy(MockBehavior::FailAfter {
           successes: 0,
           error: MockError::Timeout
       }).await;
       harness.start_daemon().await.unwrap();

       // Immediately after failure detection
       tokio::time::sleep(Duration::from_secs(3)).await;

       // Should NOT be in degradation yet (delay not passed)
       let status = harness.run_command(&["status", "--json"]);
       assert!(!status.stdout.contains("\"degraded\": true"));

       // Make mock healthy again
       mock.set_behavior(MockBehavior::Healthy { latency_ms: 50 });

       // Wait for recovery detection
       tokio::time::sleep(Duration::from_secs(3)).await;

       // Should recover without ever entering degraded state
       let status = harness.run_command(&["status", "--json"]);
       assert!(!status.stdout.contains("\"degraded\": true"));
   }
   ```

